"use client";

import * as React from "react";
import {
  PageHeader,
  Container,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  CardFooter,
  StatGroup,
  Meter,
  Delta,
  Badge,
  DataTable,
  type ColumnDef,
  MetadataList,
  AmountBreakdown,
  type AmountLine,
  ApprovalWorkflow,
  type WorkflowValue,
  SignedRecord,
  type SignedRecordValue,
  EmptyState,
  Skeleton,
  Alert,
  AlertTitle,
  AlertDescription,
  Separator,
  Button,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  VStack,
  HStack,
  Grid,
  formatCurrency,
  formatPercent,
  formatNumber,
} from "@gunjo/ui";

/* ------------------------------------------------------------------ */
/* データモデル（実データ感のあるダミー）                              */
/* ------------------------------------------------------------------ */

type TradeStatus = "on-track" | "ahead" | "behind" | "done" | "not-started";

interface TradeInput {
  id: string;
  name: string;
  /** 当初契約金額 */
  base: number;
  /** 設計変更・追加工事による増減（＋追加 / −減額） */
  change: number;
  changeNote?: string;
  /** 出来高予定率（当月末時点の予定進捗、%） */
  planned: number;
  /** 出来高実績率（実測に基づく進捗、%） */
  actual: number;
  /** 前月末の出来高実績率（%） */
  prevActual: number;
  /** 代表数量（詳細の 実測数量×単価 表示用） */
  measured?: { qty: number; unit: string; unitPrice: number };
}

const TRADE_INPUTS: TradeInput[] = [
  {
    id: "temp",
    name: "仮設工事",
    base: 28_000_000,
    change: 0,
    planned: 100,
    actual: 100,
    prevActual: 96,
    measured: { qty: 1, unit: "式", unitPrice: 28_000_000 },
  },
  {
    id: "earth",
    name: "土工事（掘削・埋戻）",
    base: 42_000_000,
    change: 3_500_000,
    changeNote: "地中障害撤去に伴う追加掘削（変更契約 第2号）",
    planned: 100,
    actual: 100,
    prevActual: 88,
    measured: { qty: 8_450, unit: "m³", unitPrice: 5_385 },
  },
  {
    id: "foundation",
    name: "基礎工事",
    base: 65_000_000,
    change: 0,
    planned: 100,
    actual: 100,
    prevActual: 92,
    measured: { qty: 1_240, unit: "m³", unitPrice: 52_419 },
  },
  {
    id: "frame",
    name: "躯体工事（RC）",
    base: 168_000_000,
    change: 6_200_000,
    changeNote: "配筋仕様変更（D22→D25、変更契約 第3号）",
    planned: 85,
    actual: 78,
    prevActual: 61,
    measured: { qty: 5_820, unit: "m³", unitPrice: 29_931 },
  },
  {
    id: "exterior",
    name: "外装・防水工事",
    base: 54_000_000,
    change: 0,
    planned: 40,
    actual: 46,
    prevActual: 22,
    measured: { qty: 3_100, unit: "m²", unitPrice: 17_419 },
  },
  {
    id: "mep",
    name: "電気・機械設備工事",
    base: 88_000_000,
    change: 2_800_000,
    changeNote: "受変電設備の容量変更（変更契約 第3号）",
    planned: 35,
    actual: 30,
    prevActual: 18,
    measured: { qty: 1, unit: "式", unitPrice: 90_800_000 },
  },
  {
    id: "interior",
    name: "内装・仕上工事",
    base: 61_000_000,
    change: 0,
    planned: 10,
    actual: 12,
    prevActual: 4,
    measured: { qty: 4_260, unit: "m²", unitPrice: 14_319 },
  },
  {
    id: "exteriorwork",
    name: "外構工事",
    base: 24_000_000,
    change: 0,
    planned: 0,
    actual: 0,
    prevActual: 0,
    measured: { qty: 1, unit: "式", unitPrice: 24_000_000 },
  },
];

interface Trade extends TradeInput {
  /** 現契約金額 = 当初 + 変更 */
  contract: number;
  /** 累計出来高額（実績率 × 現契約） */
  cumulative: number;
  /** 前月末 累計出来高額 */
  prevCumulative: number;
  /** 当月出来高額 = 累計 − 前月累計 */
  month: number;
  /** 対予定の差異（実績率 − 予定率、ポイント） */
  variance: number;
  status: TradeStatus;
}

function deriveTrade(t: TradeInput): Trade {
  const contract = t.base + t.change;
  const cumulative = Math.round((contract * t.actual) / 100);
  const prevCumulative = Math.round((contract * t.prevActual) / 100);
  const month = cumulative - prevCumulative;
  const variance = Math.round((t.actual - t.planned) * 10) / 10;
  let status: TradeStatus;
  if (t.actual === 0) status = "not-started";
  else if (t.actual >= 100) status = "done";
  else if (variance <= -3) status = "behind";
  else if (variance >= 3) status = "ahead";
  else status = "on-track";
  return { ...t, contract, cumulative, prevCumulative, month, variance, status };
}

const STATUS_META: Record<
  TradeStatus,
  { label: string; variant: "default" | "success" | "warning" | "destructive" | "secondary" | "info" | "outline" }
> = {
  done: { label: "完了", variant: "success" },
  ahead: { label: "予定より進み", variant: "info" },
  "on-track": { label: "予定どおり", variant: "secondary" },
  behind: { label: "予定より遅れ", variant: "warning" },
  "not-started": { label: "未着手", variant: "outline" },
};

/* 前払金（契約時に受領済み） */
const PREPAYMENT_TOTAL = 156_000_000;
const TAX_RATE = 0.1;

/* ------------------------------------------------------------------ */
/* 画面本体                                                            */
/* ------------------------------------------------------------------ */

export default function ProgressBillingPage() {
  const [loading, setLoading] = React.useState(true);
  const [selectedId, setSelectedId] = React.useState<string | null>(null);

  // 読み込み演出（査定データ取得）
  React.useEffect(() => {
    const id = window.setTimeout(() => setLoading(false), 900);
    return () => window.clearTimeout(id);
  }, []);

  const trades = React.useMemo(() => TRADE_INPUTS.map(deriveTrade), []);

  const totals = React.useMemo(() => {
    const contract = trades.reduce((s, t) => s + t.contract, 0);
    const baseContract = trades.reduce((s, t) => s + t.base, 0);
    const change = trades.reduce((s, t) => s + t.change, 0);
    const cumulative = trades.reduce((s, t) => s + t.cumulative, 0);
    const prevCumulative = trades.reduce((s, t) => s + t.prevCumulative, 0);
    const month = cumulative - prevCumulative;
    const remaining = contract - cumulative;
    const rate = contract > 0 ? cumulative / contract : 0;
    // 出来高請求内訳
    const thisWorkExTax = month; // 今回出来高（＝累計 − 前回まで査定確定）
    const prepaymentApplied = Math.round(thisWorkExTax * 0.3); // 前払金の当月按分戻し
    const thisBillExTax = thisWorkExTax - prepaymentApplied;
    const tax = Math.round(thisBillExTax * TAX_RATE);
    const thisBillIncTax = thisBillExTax + tax;
    return {
      contract,
      baseContract,
      change,
      cumulative,
      prevCumulative,
      month,
      remaining,
      rate,
      thisWorkExTax,
      prepaymentApplied,
      thisBillExTax,
      tax,
      thisBillIncTax,
    };
  }, [trades]);

  const selected = trades.find((t) => t.id === selectedId) ?? null;

  /* ---- 工種テーブルの列定義 ---- */
  const columns: ColumnDef<Trade>[] = React.useMemo(
    () => [
      {
        accessorKey: "name",
        header: "工種",
        cell: ({ row }) => {
          const t = row.original;
          const meta = STATUS_META[t.status];
          return (
            <VStack gap={1} align="start">
              <span className="font-medium">{t.name}</span>
              <HStack gap={2} align="center" wrap>
                <Badge variant={meta.variant} size="sm">
                  {meta.label}
                </Badge>
                {t.change !== 0 && (
                  <Badge variant="outline" size="sm">
                    変更契約あり
                  </Badge>
                )}
              </HStack>
            </VStack>
          );
        },
      },
      {
        id: "contract",
        accessorFn: (r) => r.contract,
        header: () => <div className="text-right">現契約金額</div>,
        cell: ({ row }) => (
          <div className="text-right tabular-nums">{formatCurrency(row.original.contract)}</div>
        ),
      },
      {
        id: "progress",
        accessorFn: (r) => r.actual,
        header: "出来高進捗",
        cell: ({ row }) => (
          <div className="min-w-[9rem]">
            <Meter
              value={row.original.actual}
              max={100}
              unit="%"
              direction="fill-is-good"
              size="inline"
              label={`${row.original.name} 出来高進捗率`}
            />
          </div>
        ),
      },
      {
        id: "variance",
        accessorFn: (r) => r.variance,
        header: () => <div className="text-right">対予定</div>,
        cell: ({ row }) => (
          <div className="text-right">
            <Delta
              value={row.original.variance}
              format={(v) => `${formatNumber(v, { signed: true, maximumFractionDigits: 1 })} pt`}
              labels={{ positive: "進み", negative: "遅れ", zero: "予定どおり" }}
              showLabel
            />
          </div>
        ),
      },
      {
        id: "month",
        accessorFn: (r) => r.month,
        header: () => <div className="text-right">当月出来高</div>,
        cell: ({ row }) => (
          <div className="text-right tabular-nums">{formatCurrency(row.original.month)}</div>
        ),
      },
      {
        id: "cumulative",
        accessorFn: (r) => r.cumulative,
        header: () => <div className="text-right">累計出来高</div>,
        cell: ({ row }) => (
          <div className="text-right tabular-nums">{formatCurrency(row.original.cumulative)}</div>
        ),
      },
    ],
    [],
  );

  /* ---- モバイル用カード ---- */
  const renderCard = (t: Trade) => {
    const meta = STATUS_META[t.status];
    return (
      <VStack gap={3} align="stretch">
        <HStack justify="between" align="start" gap={2}>
          <span className="font-medium">{t.name}</span>
          <Badge variant={meta.variant} size="sm">
            {meta.label}
          </Badge>
        </HStack>
        <Meter
          value={t.actual}
          max={100}
          unit="%"
          direction="fill-is-good"
          size="sm"
          label={`${t.name} 出来高進捗率`}
        />
        <Grid cols={2} gap={2}>
          <Field label="現契約金額" value={formatCurrency(t.contract)} />
          <Field
            label="対予定"
            value={
              <Delta
                value={t.variance}
                format={(v) => `${formatNumber(v, { signed: true, maximumFractionDigits: 1 })} pt`}
                labels={{ positive: "進み", negative: "遅れ", zero: "予定どおり" }}
                showLabel
              />
            }
          />
          <Field label="当月出来高" value={formatCurrency(t.month)} />
          <Field label="累計出来高" value={formatCurrency(t.cumulative)} />
        </Grid>
      </VStack>
    );
  };

  return (
    <div className="min-h-full bg-background">
      <PageHeader
        title="出来高査定・出来高請求"
        subtitle="（仮称）中央町マンション新築工事 ／ 第4回査定（2026年7月度）"
        sticky
        actions={
          <Badge variant="secondary" size="lg">
            査定期間 7/1–7/25
          </Badge>
        }
      />

      <Container size="xl" className="py-6">
        <VStack gap={6} align="stretch">
          {/* 変更・追加分の全体告知 */}
          <Alert variant="info">
            <AlertTitle as="h2">変更契約を反映済み</AlertTitle>
            <AlertDescription>
              設計変更・追加工事 3件（第2号・第3号）を今回の出来高に反映しています。変更増減の合計は{" "}
              <strong>{formatCurrency(totals.change, { signed: true })}</strong>、当初請負{" "}
              {formatCurrency(totals.baseContract)} に対し現契約金額は{" "}
              <strong>{formatCurrency(totals.contract)}</strong> です。
            </AlertDescription>
          </Alert>

          {/* 全体サマリ */}
          <section aria-labelledby="summary-heading">
            <Card>
              <CardHeader>
                <CardTitle as="h2" id="summary-heading">
                  全体サマリ
                </CardTitle>
                <CardDescription>請負金額に対する当月末時点の出来高と残高</CardDescription>
              </CardHeader>
              <CardContent>
                {loading ? (
                  <SummarySkeleton />
                ) : (
                  <VStack gap={5} align="stretch">
                    <StatGroup
                      cols={{ base: 1, sm: 2, md: 3, lg: 5 }}
                      items={[
                        { label: "請負金額（現契約）", value: formatCurrency(totals.contract) },
                        {
                          label: "累計出来高",
                          value: formatCurrency(totals.cumulative),
                          hint: `前月累計 ${formatCurrency(totals.prevCumulative)}`,
                        },
                        {
                          label: "出来高率",
                          value: formatPercent(totals.rate, { maximumFractionDigits: 1 }),
                          hint: "累計出来高 ÷ 請負金額",
                        },
                        {
                          label: "当月出来高",
                          value: formatCurrency(totals.month),
                          change: `${formatPercent(totals.month / totals.contract, {
                            maximumFractionDigits: 1,
                          })} 相当`,
                          trend: "up",
                        },
                        {
                          label: "残高（未出来高）",
                          value: formatCurrency(totals.remaining),
                          hint: "請負金額 − 累計出来高",
                        },
                      ]}
                    />
                    <div>
                      <Meter
                        value={totals.cumulative}
                        max={totals.contract}
                        direction="fill-is-good"
                        label="全体出来高率"
                        formatValue={(v) => formatCurrency(v)}
                      />
                    </div>
                  </VStack>
                )}
              </CardContent>
            </Card>
          </section>

          {/* タブ：工種別 / 請求 / 承認 */}
          <Tabs defaultValue="trades">
            <TabsList>
              <TabsTrigger value="trades">工種別出来高</TabsTrigger>
              <TabsTrigger value="billing">出来高請求</TabsTrigger>
              <TabsTrigger value="approval">査定・承認</TabsTrigger>
            </TabsList>

            {/* --- 工種別出来高（一覧 ＋ 詳細） --- */}
            <TabsContent value="trades">
              <Grid cols={{ base: 1, lg: 2 }} gap={6}>
                <section aria-labelledby="trades-heading">
                  <Card>
                    <CardHeader>
                      <CardTitle as="h2" id="trades-heading">
                        工種別 出来高一覧
                      </CardTitle>
                      <CardDescription>
                        行を選択すると右側（モバイルは下）に詳細を表示します
                      </CardDescription>
                    </CardHeader>
                    <CardContent>
                      {loading ? (
                        <TableSkeleton />
                      ) : (
                        <DataTable
                          columns={columns}
                          data={trades}
                          pageSize={20}
                          filter={{ columnId: "name", placeholder: "工種で絞り込み" }}
                          onRowClick={(t) => setSelectedId(t.id)}
                          renderCard={renderCard}
                          getRowState={(t) => (t.id === selectedId ? "selected" : undefined)}
                          caption="工種別の契約金額・出来高進捗・当月/累計出来高"
                          captionClassName="sr-only"
                          aria-labelledby="trades-heading"
                        />
                      )}
                    </CardContent>
                  </Card>
                </section>

                <section aria-labelledby="detail-heading" className="lg:sticky lg:top-24 lg:self-start">
                  {loading ? (
                    <Card>
                      <CardHeader>
                        <CardTitle as="h2" id="detail-heading">
                          工種の詳細
                        </CardTitle>
                      </CardHeader>
                      <CardContent>
                        <DetailSkeleton />
                      </CardContent>
                    </Card>
                  ) : selected ? (
                    <TradeDetail trade={selected} onClose={() => setSelectedId(null)} />
                  ) : (
                    <Card>
                      <CardHeader className="sr-only">
                        <CardTitle as="h2" id="detail-heading">
                          工種の詳細
                        </CardTitle>
                      </CardHeader>
                      <CardContent>
                        <EmptyState
                          headingLevel={3}
                          title="工種を選択してください"
                          description="一覧から工種を選ぶと、実測数量・単価、予定に対する進捗、変更契約の内訳を確認できます。"
                        />
                      </CardContent>
                    </Card>
                  )}
                </section>
              </Grid>
            </TabsContent>

            {/* --- 出来高請求 --- */}
            <TabsContent value="billing">
              <section aria-labelledby="billing-heading">
                <Card>
                  <CardHeader>
                    <CardTitle as="h2" id="billing-heading">
                      出来高請求内訳（第4回）
                    </CardTitle>
                    <CardDescription>
                      累計出来高から前回まで請求済み・前払金充当を差し引いて今回請求額を算定
                    </CardDescription>
                  </CardHeader>
                  <CardContent>
                    {loading ? (
                      <DetailSkeleton />
                    ) : (
                      <AmountBreakdown
                        lines={billingLines(totals)}
                        total={{
                          label: "今回ご請求額（税込）",
                          amount: totals.thisBillIncTax,
                          tone: "neutral",
                        }}
                        formula="今回ご請求額 = 累計出来高 − 前回まで請求済 − 前払金充当 ＋ 消費税"
                      />
                    )}
                  </CardContent>
                  <CardFooter>
                    <p className="text-sm text-muted-foreground">
                      前払金 {formatCurrency(PREPAYMENT_TOTAL)}（請負金額の約30%）は、出来高に応じて
                      各回で按分精算します。今回充当分は{" "}
                      {formatCurrency(totals.prepaymentApplied)} です。
                    </p>
                  </CardFooter>
                </Card>
              </section>
            </TabsContent>

            {/* --- 査定・承認 --- */}
            <TabsContent value="approval">
              <VStack gap={6} align="stretch">
                <ApprovalSection />
              </VStack>
            </TabsContent>
          </Tabs>
        </VStack>
      </Container>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* 出来高請求 明細行                                                   */
/* ------------------------------------------------------------------ */

function billingLines(t: {
  cumulative: number;
  prevCumulative: number;
  thisWorkExTax: number;
  prepaymentApplied: number;
  thisBillExTax: number;
  tax: number;
}): AmountLine[] {
  return [
    { type: "heading", label: "出来高（税抜）" },
    { label: "累計出来高", amount: t.cumulative, note: "当月末までの査定額（全工種合計）" },
    {
      label: "前回まで請求済出来高",
      amount: t.prevCumulative,
      kind: "subtract",
      note: "第3回までに査定確定・請求済み",
    },
    { type: "subtotal", label: "今回出来高（税抜）", amount: t.thisWorkExTax },
    {
      label: "前払金充当（当月按分）",
      amount: t.prepaymentApplied,
      kind: "subtract",
      note: "受領済み前払金の出来高按分戻し（30%）",
    },
    { type: "subtotal", label: "今回請求額（税抜）", amount: t.thisBillExTax },
    { label: "消費税（10%）", amount: t.tax },
  ];
}

/* ------------------------------------------------------------------ */
/* 工種詳細                                                            */
/* ------------------------------------------------------------------ */

function TradeDetail({ trade, onClose }: { trade: Trade; onClose: () => void }) {
  const meta = STATUS_META[trade.status];
  const changeLines: AmountLine[] = [
    { label: "当初契約金額", amount: trade.base },
    ...(trade.change !== 0
      ? [
          {
            label: "設計変更・追加工事",
            amount: Math.abs(trade.change),
            kind: (trade.change >= 0 ? "add" : "subtract") as "add" | "subtract",
            note: trade.changeNote,
          } as AmountLine,
        ]
      : []),
  ];

  return (
    <Card>
      <CardHeader>
        <HStack justify="between" align="start" gap={2}>
          <VStack gap={1} align="start">
            <CardTitle as="h2" id="detail-heading">
              {trade.name}
            </CardTitle>
            <Badge variant={meta.variant} size="sm">
              {meta.label}
            </Badge>
          </VStack>
          <Button variant="ghost" size="sm" onClick={onClose}>
            閉じる
          </Button>
        </HStack>
      </CardHeader>
      <CardContent>
        <VStack gap={5} align="stretch">
          <div>
            <Meter
              value={trade.actual}
              max={100}
              unit="%"
              direction="fill-is-good"
              target={trade.planned}
              label={`${trade.name} 出来高進捗率`}
            />
            <HStack gap={2} align="center" className="mt-2">
              <span className="text-sm text-muted-foreground">対予定</span>
              <Delta
                value={trade.variance}
                format={(v) => `${formatNumber(v, { signed: true, maximumFractionDigits: 1 })} pt`}
                labels={{ positive: "進み", negative: "遅れ", zero: "予定どおり" }}
                showLabel
              />
              <span className="text-sm text-muted-foreground">
                （予定 {trade.planned}% ／ 実績 {trade.actual}%）
              </span>
            </HStack>
          </div>

          <Separator />

          <MetadataList
            layout="horizontal"
            items={[
              {
                label: "実測数量 × 単価",
                value: trade.measured
                  ? `${formatNumber(trade.measured.qty)} ${trade.measured.unit} × ${formatCurrency(
                      trade.measured.unitPrice,
                    )}`
                  : "—",
              },
              { label: "前月末 累計出来高", value: formatCurrency(trade.prevCumulative) },
              { label: "当月出来高", value: formatCurrency(trade.month) },
              { label: "累計出来高", value: formatCurrency(trade.cumulative) },
              { label: "残（未出来高）", value: formatCurrency(trade.contract - trade.cumulative) },
            ]}
          />

          <div>
            <h3 className="mb-2 text-sm font-medium text-muted-foreground">変更契約の内訳</h3>
            <AmountBreakdown
              lines={changeLines}
              total={{
                label: "現契約金額",
                amount: trade.contract,
                tone: trade.change > 0 ? "positive" : trade.change < 0 ? "negative" : "neutral",
              }}
            />
          </div>
        </VStack>
      </CardContent>
    </Card>
